  1→import type { StateHandler, RunContext, RunState } from "../types.js";
  2→import type { StateHandlerMap } from "./engine.js";
  3→import type { GitAdapter } from "../adapters/git.js";
  4→import type { GitHubAdapter } from "../adapters/github.js";
  5→import { runPlanner } from "../agents/planner.js";
  6→import { runImplementer } from "../agents/implementer.js";
  7→import { runReviewer } from "../agents/reviewer.js";
  8→import { runFixer } from "../agents/fixer.js";
  9→import type { Logger } from "../util/logger.js";
 10→import type { DocumenterInput } from "../agents/documenter.js";
 11→import {
 12→  parseIssueConfig,
 13→  type ResolvedConfig,
 14→} from "../config/issue-config.js";
 15→import type { IssueConfig } from "../config/issue-config.js";
 16→import { mergeConfigs } from "../config/merge-config.js";
 17→import {
 18→  buildResolvedConfigBlock,
 19→  upsertAidevBlock,
 20→} from "../config/serialize-config.js";
 21→import type { SkippableState } from "../types.js";
 22→import type { Issue, PullRequest } from "../adapters/github.js";
 23→
 24→export interface Deps {
 25→  git: GitAdapter;
 26→  github: GitHubAdapter;
 27→  logger: Logger;
 28→  runDocumenter: (input: DocumenterInput, logger: Logger) => Promise<void>;
 29→  loadRepoConfig: (cwd: string) => Promise<Partial<IssueConfig>>;
 30→}
 31→
 32→function transition(
 33→  ctx: RunContext,
 34→  nextState: RunState,
 35→  patch?: Partial<RunContext>,
 36→) {
 37→  return { nextState, ctx: { ...ctx, ...patch, state: nextState } };
 38→}
 39→
 40→function shouldAutoMerge(ctx: RunContext): boolean {
 41→  return ctx.autoMerge || ctx.issueLabels.includes("auto-merge");
 42→}
 43→
 44→function toPlanningTarget(workItem: Issue | PullRequest): Issue {
 45→  return {
 46→    number: workItem.number,
 47→    title: workItem.title,
 48→    body: workItem.body,
 49→    labels: "labels" in workItem ? workItem.labels : [],
 50→    author: workItem.author,
 51→  };
 52→}
 53→
 54→export function createStateHandlers(deps: Deps): StateHandlerMap {
 55→  const { git, github, logger, runDocumenter, loadRepoConfig } = deps;
 56→
 57→  const init: StateHandler = async (ctx) => {
 58→    if (ctx.targetKind === "pr") {
 59→      const pr = await github.getPr(ctx.prNumber!);
 60→      logger.info("Fetched PR", {
 61→        number: pr.number,
 62→        title: pr.title,
 63→      });
 64→
 65→      if (!ctx.skipAuthorCheck) {
 66→        const authenticatedUser = await github.getAuthenticatedUser();
 67→        if (pr.author !== authenticatedUser) {
 68→          throw new Error(
 69→            `PR #${pr.number} was created by '${pr.author}', not by the authenticated user '${authenticatedUser}'. Use --allow-foreign-issues to bypass this check.`,
 70→          );
 71→        }
 72→      }
 73→
 74→      const patch: Partial<RunContext> = {
 75→        issueLabels: [],
 76→        issueTitle: pr.title,
 77→        base: ctx._cliExplicit?.has("base") ? ctx.base : pr.baseRefName,
 78→        branch: pr.headRefName,
 79→        headBranch: pr.headRefName,
 80→      };
 81→
 82→      const mergedCtx = { ...ctx, ...patch };
 83→      await git.createBranch(
 84→        mergedCtx.branch,
 85→        `origin/${pr.headRefName}`,
 86→        mergedCtx.cwd,
 87→      );
 88→      logger.info("Checked out PR head branch", {
 89→        branch: mergedCtx.branch,
 90→        base: mergedCtx.base,
 91→      });
 92→      return transition(mergedCtx, "planning");
 93→    }
 94→
 95→    const issue = await github.getIssue(ctx.issueNumber!);
 96→    logger.info("Fetched issue", {
 97→      number: issue.number,
 98→      title: issue.title,
 99→    });
100→
101→    if (!ctx.skipAuthorCheck) {
102→      const authenticatedUser = await github.getAuthenticatedUser();
103→      if (issue.author !== authenticatedUser) {
104→        throw new Error(
105→          `Issue #${issue.number} was created by '${issue.author}', not by the authenticated user '${authenticatedUser}'. Use --allow-foreign-issues to bypass this check.`,
106→        );
107→      }
108→    }
109→
110→    // Load repo-level config (.aidev.yml)
111→    const repoConfig = await loadRepoConfig(ctx.cwd);
112→    if (Object.keys(repoConfig).length > 0) {
113→      logger.info("Loaded repo config", { repoConfig });
114→    }
115→
116→    // Parse issue config from body
117→    const issueConfig = parseIssueConfig(issue.body);
118→    if (Object.keys(issueConfig).length > 0) {
119→      logger.info("Parsed issue config", { issueConfig });
120→    }
121→
122→    // Merge: repo < issue, excluding CLI-explicit fields
123→    const cliExplicit = ctx._cliExplicit ?? new Set<string>();
124→    const merged = mergeConfigs(repoConfig, issueConfig, cliExplicit);
125→
126→    const patch: Partial<RunContext> = {
127→      issueLabels: issue.labels,
128→      issueTitle: issue.title,
129→    };
130→
131→    if (merged.maxFixAttempts !== undefined)
132→      patch.maxFixAttempts = merged.maxFixAttempts;
133→    if (merged.autoMerge !== undefined) patch.autoMerge = merged.autoMerge;
134→    if (merged.dryRun !== undefined) patch.dryRun = merged.dryRun;
135→    if (merged.base !== undefined) patch.base = merged.base;
136→    if (merged.skip) patch.skipStates = merged.skip as SkippableState[];
137→    if (merged.stateTimeouts) patch.stateTimeouts = merged.stateTimeouts;
138→
139→    const mergedCtx = { ...ctx, ...patch };
140→
141→    // Build resolved config and write back to issue body
142→    const resolvedConfig: ResolvedConfig = {
143→      maxFixAttempts: mergedCtx.maxFixAttempts,
144→      autoMerge: mergedCtx.autoMerge,
145→      dryRun: mergedCtx.dryRun,
146→      base: mergedCtx.base,
147→      skip: (mergedCtx.skipStates ?? []) as SkippableState[],
148→    };
149→    const configBlock = buildResolvedConfigBlock(resolvedConfig);
150→    const updatedBody = upsertAidevBlock(issue.body, configBlock);
151→    await github.updateIssueBody(issue.number, updatedBody);
152→
153→    await git.createBranch(mergedCtx.branch, mergedCtx.base, mergedCtx.cwd);
154→    logger.info("Created branch", { branch: mergedCtx.branch });
155→    return transition(mergedCtx, "planning");
156→  };
157→
158→  const planning: StateHandler = async (ctx) => {
159→    const workItem =
160→      ctx.targetKind === "pr"
161→        ? toPlanningTarget(await github.getPr(ctx.prNumber!))
162→        : await github.getIssue(ctx.issueNumber!);
163→    const planStart = performance.now();
164→    const plan = await runPlanner({ issue: workItem, cwd: ctx.cwd }, logger);
165→    const planElapsed = Math.round(performance.now() - planStart);
166→    logger.info("Plan created", {
167→      summary: plan.summary,
168→      agentElapsedMs: planElapsed,
169→    });
170→
171→    if (plan.investigation) {
172→      const comment = `## 🔍 Investigation\n\n${plan.investigation}\n\n## Plan\n\n${plan.steps.map((s, i) => `${i + 1}. ${s}`).join("\n")}`;
173→      if (ctx.targetKind === "pr") {
174→        await github.commentOnPr(ctx.prNumber!, comment);
175→        logger.info("Posted investigation to PR", { pr: ctx.prNumber });
176→      } else {
177→        await github.commentOnIssue(ctx.issueNumber!, comment);
178→        logger.info("Posted investigation to issue", {
179→          issue: ctx.issueNumber,
180→        });
181→      }
182→    }
183→
184→    return transition(ctx, "implementing", { plan });
185→  };
186→
187→  const implementing: StateHandler = async (ctx) => {
188→    if (!ctx.plan) throw new Error("No plan available");
189→    const implStart = performance.now();
190→    const result = await runImplementer(
191→      {
192→        plan: ctx.plan,
193→        workItemKind: ctx.targetKind,
194→        workItemNumber:
195→          ctx.targetKind === "pr" ? ctx.prNumber! : ctx.issueNumber!,
196→        cwd: ctx.cwd,
197→      },
198→      logger,
199→    );
200→    const implElapsed = Math.round(performance.now() - implStart);
201→    logger.info("Implementation complete", {
202→      changedFiles: result.changedFiles,
203→      agentElapsedMs: implElapsed,
204→    });
205→    return transition(ctx, "reviewing", { result });
206→  };
207→
208→  const reviewing: StateHandler = async (ctx) => {
209→    if (ctx.skipStates?.includes("reviewing")) {
210→      logger.info("Skipping reviewing (configured in issue)");
211→      return transition(ctx, "committing");
212→    }
213→    if (!ctx.plan) throw new Error("No plan available");
214→    const diff = await git.diff(ctx.base, ctx.cwd);
215→    const reviewStart = performance.now();
216→    const review = await runReviewer(
217→      { plan: ctx.plan, diff, cwd: ctx.cwd },
218→      logger,
219→    );
220→    const reviewElapsed = Math.round(performance.now() - reviewStart);
221→    logger.info("Review complete", {
222→      decision: review.decision,
223→      agentElapsedMs: reviewElapsed,
224→    });
225→
226→    if (review.decision === "changes_requested") {
227→      return transition(ctx, "implementing", { review });
228→    }
229→    return transition(ctx, "committing", { review });
230→  };
231→
232→  const committing: StateHandler = async (ctx) => {
233→    if (!ctx.result) throw new Error("No result available");
234→    if (ctx.skipStates?.includes("documenter")) {
235→      logger.info("Skipping documenter (configured in issue)");
236→    } else {
237→      await runDocumenter({ result: ctx.result, cwd: ctx.cwd }, logger);
238→    }
239→    logger.info("Documentation check completed");
240→    await git.addAll(ctx.cwd);
241→    await git.commit(ctx.result.commitMessageDraft, ctx.cwd);
242→    logger.info("Committed changes");
243→
244→    if (ctx.dryRun) {
245→      logger.info("Dry run - skipping push and PR creation");
246→      return transition(ctx, "done");
247→    }
248→    return transition(ctx, "creating_pr");
249→  };
250→
251→  const creating_pr: StateHandler = async (ctx) => {
252→    if (!ctx.result) throw new Error("No result available");
253→    if (ctx.targetKind === "pr") {
254→      await git.push(ctx.headBranch ?? ctx.branch, ctx.cwd);
255→      logger.info("Updated existing PR branch", {
256→        prNumber: ctx.prNumber,
257→        branch: ctx.headBranch ?? ctx.branch,
258→      });
259→      return transition(ctx, "watching_ci", { prNumber: ctx.prNumber });
260→    }
261→    await git.push(ctx.branch, ctx.cwd);
262→    const prNumber = await github.createPr({
263→      title: ctx.result.commitMessageDraft.split("\n")[0]!,
264→      body: ctx.result.prBodyDraft,
265→      head: ctx.branch,
266→      base: ctx.base,
267→    });
268→    logger.info("PR created", { prNumber });
269→    return transition(ctx, "watching_ci", { prNumber });
270→  };
271→
272→  const watching_ci: StateHandler = async (ctx) => {
273→    if (!ctx.prNumber) throw new Error("No PR number");
274→    if (ctx.skipStates?.includes("watching_ci")) {
275→      logger.info("Skipping watching_ci (configured in issue)");
276→      if (!shouldAutoMerge(ctx)) return transition(ctx, "done");
277→      return transition(ctx, "merging");
278→    }
279→    const maxWait = 10 * 60 * 1000; // 10 minutes
280→    const pollInterval = 15 * 1000; // 15 seconds
281→    const gracePeriod = 30 * 1000; // 30 seconds for CI check runs to register
282→    const start = Date.now();
283→
284→    while (Date.now() - start < maxWait) {
285→      const status = await github.getCiStatus(ctx.branch);
286→      if (status === "passing") {
287→        logger.info("CI passed");
288→        if (!shouldAutoMerge(ctx)) return transition(ctx, "done");
289→        return transition(ctx, "merging");
290→      }
291→      if (status === "failing") {
292→        logger.warn("CI failed");
293→        if (ctx.fixAttempts >= ctx.maxFixAttempts) {
294→          logger.error("Max fix attempts exceeded");
295→          return transition(ctx, "failed");
296→        }
297→        return transition(ctx, "fixing", {
298→          fixAttempts: ctx.fixAttempts + 1,
299→        });
300→      }
301→      if (status === "no_checks" && Date.now() - start >= gracePeriod) {
302→        logger.info(
303→          "No CI checks found after grace period, treating as passing",
304→        );
305→        if (!shouldAutoMerge(ctx)) return transition(ctx, "done");
306→        return transition(ctx, "merging");
307→      }
308→      await new Promise((r) => setTimeout(r, pollInterval));
309→    }
310→
311→    logger.error("CI timed out");
312→    return transition(ctx, "failed");
313→  };
314→
315→  const fixing: StateHandler = async (ctx) => {
316→    if (!ctx.plan) throw new Error("No plan available");
317→    const ciLog = await github.getCheckRunLogs(ctx.branch);
318→    const fixStart = performance.now();
319→    const fix = await runFixer({ plan: ctx.plan, ciLog, cwd: ctx.cwd }, logger);
320→    const fixElapsed = Math.round(performance.now() - fixStart);
321→    logger.info("Fix applied", {
322→      rootCause: fix.rootCause,
323→      agentElapsedMs: fixElapsed,
324→    });
325→
326→    await git.addAll(ctx.cwd);
327→    await git.commit(`fix: ${fix.rootCause}`, ctx.cwd);
328→    await git.push(ctx.branch, ctx.cwd);
329→    return transition(ctx, "watching_ci", { fix });
330→  };
331→
332→  const merging: StateHandler = async (ctx) => {
