  1→import { Command } from "commander";
  2→import { randomUUID } from "node:crypto";
  3→import { mkdir, writeFile, readFile } from "node:fs/promises";
  4→import { join } from "node:path";
  5→import { createInterface } from "node:readline";
  6→import { createGitAdapter } from "./adapters/git.js";
  7→import {
  8→  createGitHubAdapter,
  9→  type Issue,
 10→  type PullRequest,
 11→} from "./adapters/github.js";
 12→import { createLogger } from "./util/logger.js";
 13→import { runWorkflow, type Persistence } from "./workflow/engine.js";
 14→import { createStateHandlers } from "./workflow/states.js";
 15→import { runDocumenter } from "./agents/documenter.js";
 16→import { createSlackNotifier, formatSlackMessage } from "./adapters/slack.js";
 17→import { loadRepoConfig } from "./config/repo-config.js";
 18→import { writeAidevYml } from "./config/init.js";
 19→import type { RunContext } from "./types.js";
 20→
 21→function createFilePersistence(baseDir: string): Persistence {
 22→  return {
 23→    async save(ctx) {
 24→      const dir = join(baseDir, ctx.runId);
 25→      await mkdir(dir, { recursive: true });
 26→      await writeFile(join(dir, "state.json"), JSON.stringify(ctx, null, 2));
 27→
 28→      if (ctx.plan)
 29→        await writeFile(
 30→          join(dir, "plan.json"),
 31→          JSON.stringify(ctx.plan, null, 2),
 32→        );
 33→      if (ctx.result)
 34→        await writeFile(
 35→          join(dir, "result.json"),
 36→          JSON.stringify(ctx.result, null, 2),
 37→        );
 38→      if (ctx.review)
 39→        await writeFile(
 40→          join(dir, "review.json"),
 41→          JSON.stringify(ctx.review, null, 2),
 42→        );
 43→      if (ctx.fix)
 44→        await writeFile(
 45→          join(dir, "fix.json"),
 46→          JSON.stringify(ctx.fix, null, 2),
 47→        );
 48→    },
 49→    async load(runId) {
 50→      try {
 51→        const data = await readFile(
 52→          join(baseDir, runId, "state.json"),
 53→          "utf-8",
 54→        );
 55→        return JSON.parse(data) as RunContext;
 56→      } catch {
 57→        return null;
 58→      }
 59→    },
 60→    async findLatestByIssue(issueNumber) {
 61→      const { readdir } = await import("node:fs/promises");
 62→      let dirs: string[];
 63→      try {
 64→        dirs = await readdir(baseDir);
 65→      } catch {
 66→        return null;
 67→      }
 68→      // Sort descending by timestamp (embedded in dir name)
 69→      dirs.sort().reverse();
 70→      for (const dir of dirs) {
 71→        try {
 72→          const data = await readFile(
 73→            join(baseDir, dir, "state.json"),
 74→            "utf-8",
 75→          );
 76→          const ctx = JSON.parse(data) as RunContext;
 77→          if (ctx.issueNumber === issueNumber) return ctx;
 78→        } catch {
 79→          continue;
 80→        }
 81→      }
 82→      return null;
 83→    },
 84→    async findLatestByPr(prNumber) {
 85→      const { readdir } = await import("node:fs/promises");
 86→      let dirs: string[];
 87→      try {
 88→        dirs = await readdir(baseDir);
 89→      } catch {
 90→        return null;
 91→      }
 92→      dirs.sort().reverse();
 93→      for (const dir of dirs) {
 94→        try {
 95→          const data = await readFile(
 96→            join(baseDir, dir, "state.json"),
 97→            "utf-8",
 98→          );
 99→          const ctx = JSON.parse(data) as RunContext;
100→          if (ctx.prNumber === prNumber && ctx.targetKind === "pr") return ctx;
101→        } catch {
102→          continue;
103→        }
104→      }
105→      return null;
106→    },
107→  };
108→}
109→
110→function detectRepo(cwd: string): string {
111→  // Try to detect from git remote, fallback to env
112→  return process.env.DEVLOOP_REPO ?? "mizumura3/inko";
113→}
114→
115→export function createCli() {
116→  const program = new Command();
117→
118→  program
119→    .name("aidev")
120→    .description("AI-powered development loop")
121→    .version("0.0.1");
122→
123→  const runCmd = program
124→    .command("run")
125→    .description("Run the full dev loop for an issue or pull request")
126→    .option("--issue <number>", "GitHub issue number", parseInt)
127→    .option("--pr <number>", "GitHub pull request number", parseInt)
128→    .option("--cwd <path>", "Working directory", process.cwd())
129→    .option("--max-fix-attempts <n>", "Max CI fix attempts", parseInt, 3)
130→    .option("--dry-run", "Skip push/PR/merge", false)
131→    .option("--auto-merge", "Merge PR and close issue after CI passes", false)
132→    .option(
133→      "--base <branch>",
134→      "Base branch or tag to create branch from",
135→      "main",
136→    )
137→    .option("--repo <owner/name>", "GitHub repo (owner/name)")
138→    .option("--claude-path <path>", "Path to native Claude Code executable")
139→    .option("--resume", "Resume the latest run for this target")
140→    .option("-y, --yes", "Skip interactive confirmation", false)
141→    .option(
142→      "--allow-foreign-issues",
143→      "Allow processing issues or PRs from other users",
144→      false,
145→    );
146→
147→  runCmd.action(async (opts) => {
148→    if (opts.claudePath) process.env.CLAUDE_EXECUTABLE = opts.claudePath;
149→    const logger = createLogger("info");
150→    const baseDir = join(process.env.HOME ?? "~", ".devloop", "runs");
151→    const persistence = createFilePersistence(baseDir);
152→    const targetKind = opts.pr != null ? "pr" : "issue";
153→    const targetNumber = targetKind === "pr" ? opts.pr : opts.issue;
154→
155→    if (
156→      (opts.issue == null && opts.pr == null) ||
157→      (opts.issue != null && opts.pr != null)
158→    ) {
159→      logger.error("Specify exactly one of --issue or --pr");
160→      process.exit(1);
161→    }
162→
163→    let ctx: RunContext;
164→
165→    if (opts.resume) {
166→      const saved =
167→        targetKind === "pr"
168→          ? await persistence.findLatestByPr?.(opts.pr)
169→          : await persistence.findLatestByIssue?.(opts.issue);
170→      if (!saved) {
171→        logger.error("No previous run found for target", {
172→          targetKind,
173→          targetNumber,
174→        });
175→        process.exit(1);
176→      }
177→      // Override flags for resumed run
178→      ctx = {
179→        ...saved,
180→        dryRun: opts.dryRun,
181→        autoMerge: opts.autoMerge,
182→      };
183→      // If previous run completed as done (dry-run), restart from creating_pr
184→      // (commit already exists, just need push + PR)
185→      if (saved.state === "done" && saved.dryRun) {
186→        ctx.state = "creating_pr";
187→      }
188→      // If previous run ended in manual_handoff, restart from the timed-out state
189→      if (saved.state === "manual_handoff" && saved._timedOutState) {
190→        ctx.state = saved._timedOutState as RunContext["state"];
191→        ctx.handoffReason = undefined;
192→        ctx.handoffContext = undefined;
193→        ctx._timedOutState = undefined;
194→      }
195→      logger.info("Resuming run", {
196→        runId: ctx.runId,
197→        fromState: ctx.state,
198→        targetKind,
199→        targetNumber,
200→      });
201→    } else {
202→      const runId = `run-${Date.now()}-${randomUUID().slice(0, 8)}`;
203→      const cwd = opts.cwd;
204→      const repo = opts.repo ?? detectRepo(cwd);
205→      const ghForConfirm = createGitHubAdapter(repo);
206→
207→      let issue: Issue | undefined;
208→      let pr: PullRequest | undefined;
209→      let branch: string;
210→
211→      if (targetKind === "pr") {
212→        pr = await ghForConfirm.getPr(opts.pr);
213→        branch = pr.headRefName;
214→      } else {
215→        issue = await ghForConfirm.getIssue(opts.issue);
216→        branch = `aidev/issue-${opts.issue}`;
217→      }
218→
219→      const target = targetKind === "pr" ? pr! : issue!;
220→
221→      if (!opts.yes) {
222→        if (process.stdin.isTTY) {
223→          const truncated =
224→            target.body && target.body.length > 500
225→              ? target.body.slice(0, 500) + "..."
226→              : target.body;
227→          console.log(
228→            `\n--- ${targetKind.toUpperCase()} #${target.number}: ${target.title} ---`,
229→          );
230→          console.log(`Author: ${target.author}`);
231→          if (truncated) console.log(`\n${truncated}\n`);
232→
233→          const confirmed = await new Promise<boolean>((resolve) => {
234→            const rl = createInterface({
235→              input: process.stdin,
236→              output: process.stdout,
237→            });
238→            rl.question("Proceed with this issue? (y/N) ", (answer) => {
239→              rl.close();
240→              resolve(answer.toLowerCase() === "y");
241→            });
242→          });
243→
244→          if (!confirmed) {
245→            logger.info("Cancelled by user");
246→            process.exit(0);
247→          }
248→        } else {
249→          logger.info(
250→            "Non-interactive mode: skipping confirmation (use --yes to suppress this message)",
251→          );
252→        }
253→      }
254→
255→      // Track which flags were explicitly set via CLI
256→      const cliExplicit = new Set<string>();
257→      const flagMap: Record<string, string> = {
258→        maxFixAttempts: "max-fix-attempts",
259→        dryRun: "dry-run",
260→        autoMerge: "auto-merge",
261→        base: "base",
262→      };
263→      for (const [ctxKey, cliName] of Object.entries(flagMap)) {
264→        if (runCmd.getOptionValueSource(cliName) === "cli") {
265→          cliExplicit.add(ctxKey);
266→        }
267→      }
268→
269→      ctx = {
270→        runId,
271→        targetKind,
272→        issueNumber: opts.issue,
273→        prNumber: opts.pr,
274→        repo,
275→        cwd,
276→        state: "init",
277→        branch,
278→        headBranch: pr?.headRefName,
279→        base: opts.base,
280→        maxFixAttempts: opts.maxFixAttempts,
281→        fixAttempts: 0,
282→        dryRun: opts.dryRun,
283→        autoMerge: opts.autoMerge,
284→        issueLabels: [],
285→        skipStates: [],
286→        skipAuthorCheck: opts.allowForeignIssues,
287→        _cliExplicit: cliExplicit.size > 0 ? cliExplicit : undefined,
288→      };
289→    }
290→
291→    const git = createGitAdapter();
