  1→import { z } from "zod";
  2→import { SkippableStateSchema } from "../types.js";
  3→import type { SkippableState } from "../types.js";
  4→
  5→export type { SkippableState } from "../types.js";
  6→
  7→const IssueConfigSchema = z
  8→  .object({
  9→    maxFixAttempts: z.number().int().positive().optional(),
 10→    autoMerge: z.boolean().optional(),
 11→    dryRun: z.boolean().optional(),
 12→    base: z.string().optional(),
 13→    skip: z.array(SkippableStateSchema).optional(),
 14→    stateTimeouts: z.record(z.string(), z.number()).optional(),
 15→  })
 16→  .strict();
 17→
 18→export type IssueConfig = z.infer<typeof IssueConfigSchema>;
 19→
 20→export interface ResolvedConfig {
 21→  maxFixAttempts: number;
 22→  autoMerge: boolean;
 23→  dryRun: boolean;
 24→  base: string;
 25→  skip: SkippableState[];
 26→  stateTimeouts?: Record<string, number>;
 27→}
 28→
 29→/**
 30→ * Extract the content inside the first ```aidev ... ``` code fence.
 31→ */
 32→function extractAidevBlock(body: string): string | null {
 33→  const match = body.match(/```aidev\s*\n([\s\S]*?)```/);
 34→  return match?.[1] ?? null;
 35→}
