 42→describe("runWorkflow", () => {
 43→  it("transitions init → planning → implementing → ... → done", async () => {
 44→    const handlers: StateHandlerMap = {
 45→      init: makeHandler("planning"),
 46→      planning: makeHandler("implementing"),
 47→      implementing: makeHandler("reviewing"),
 48→      reviewing: makeHandler("committing"),
 49→      committing: makeHandler("creating_pr"),
 50→      creating_pr: makeHandler("watching_ci"),
 51→      watching_ci: makeHandler("merging"),
 52→      merging: makeHandler("closing_issue"),
 53→      closing_issue: makeHandler("done"),
 54→    };
