 57→
 58→    const result = await runWorkflow(ctx, handlers, persistence);
 59→
 60→    expect(result.state).toBe("done");
 61→    expect(handlers.init).toHaveBeenCalledOnce();
 62→    expect(handlers.planning).toHaveBeenCalledOnce();
 63→    expect(handlers.closing_issue).toHaveBeenCalledOnce();
 64→  });
 65→
 66→  it("persists state after each transition", async () => {
 67→    const handlers: StateHandlerMap = {
 68→      init: makeHandler("planning"),
 69→      planning: makeHandler("done"),
 70→    };
 71→    const persistence = makePersistence();
 72→    const ctx = makeCtx();
 73→
 74→    await runWorkflow(ctx, handlers, persistence);
 75→
 76→    // init -> planning (save), planning -> done (save)
 77→    expect(persistence.save).toHaveBeenCalledTimes(2);
 78→  });
 79→
 80→  it("handles reviewing → implementing (changes_requested)", async () => {
 81→    let reviewCount = 0;
 82→    const handlers: StateHandlerMap = {
 83→      init: makeHandler("planning"),
 84→      planning: makeHandler("implementing"),
 85→      implementing: makeHandler("reviewing"),
 86→      reviewing: vi.fn(async (ctx) => {
 87→        reviewCount++;
