116→        ciCount++;
117→        if (ciCount === 1) {
118→          return {
119→            nextState: "fixing" as RunState,
120→            ctx: {
121→              ...ctx,
122→              state: "fixing" as RunState,
123→              fixAttempts: ctx.fixAttempts + 1,
124→            },
125→          };
126→        }
127→        return {
128→          nextState: "done" as RunState,
129→          ctx: { ...ctx, state: "done" as RunState },
130→        };
131→      }),
132→      fixing: makeHandler("watching_ci"),
133→    };
134→    const persistence = makePersistence();
135→    const ctx = makeCtx();
136→
137→    const result = await runWorkflow(ctx, handlers, persistence);
138→
139→    expect(result.state).toBe("done");
140→    expect(handlers.fixing).toHaveBeenCalledOnce();
141→    expect(ciCount).toBe(2);
